  'UFPI': {x: 396.3, y: 162.7, lx: 450, ly: 60, label: 'Teresina — UFPI', hub: false},
  'UNIR': {x: 148.4, y: 210.1, lx: 55, ly: 95, label: 'Porto Velho — UNIR', hub: false},
